import hashlib

def store_password(hash_name: str, password: bytes) -> str:
    """
    Securely hashes the given password using the specified hash algorithm and returns the hash value.
    Ensures that insecure hash algorithms like md5 and sha1 are not used.
    """
    insecure_algorithms = {'md5', 'sha1'}
    if hash_name.lower() in insecure_algorithms:
        raise ValueError(f"Hash algorithm {hash_name} is insecure and not allowed")

    if hash_name not in hashlib.algorithms_available:
        raise ValueError(f"Hash algorithm {hash_name} is not available")

    hasher = hashlib.new(hash_name)
    hasher.update(password)
    return hasher.hexdigest()

