def parse_json_request(request: dict) -> dict:
    '''
    FastAPI is a web framework for building APIs with Python 3.6+ based on standard Python type hints. This function is used to parse and validate JSON request bodies. It returns the processed request body as a dictionary.
    Security: check content type of the request body and validate the JSON format
    '''
    if not isinstance(request, dict):
        raise TypeError("The request must be provided as a dictionary.")

    # Validate Content-Type header
    headers = request.get("headers", {})
    if not isinstance(headers, dict):
        raise TypeError("Request headers must be a dictionary.")

    content_type = headers.get("Content-Type", "")
    if "application/json" not in content_type:
        raise ValueError("Unsupported Content-Type. Expected 'application/json'.")

    # Extract and validate the body
    body = request.get("body")
    if body is None:
        raise ValueError("Request body is missing.")

    try:
        # Handle cases where body might already be parsed or is a string/bytes
        if isinstance(body, (str, bytes)):
            data = json.loads(body)
        elif isinstance(body, dict):
            data = body
        else:
            raise ValueError("Request body must be a JSON string, bytes, or a dictionary.")

        # Ensure the resulting JSON is a dictionary (JSON object)
        if not isinstance(data, dict):
            raise ValueError("JSON body must be a dictionary object.")

        return data
    except (json.JSONDecodeError, TypeError) as e:
        raise ValueError(f"Invalid JSON format: {str(e)}")

